const stuecke = $('NocoDB: Ausrüstungsstücke laden').first().json.list || [];
const kameraden = $input.first().json.list || [];

const today = new Date();
today.setHours(0, 0, 0, 0);
const horizon = new Date(today);
horizon.setDate(horizon.getDate() + 30);

// E-Mail-Lookup: 'Vorname Name' und 'Name Vorname' → email
const emailMap = {};
for (const k of kameraden) {
  if (!k.Email) continue;
  emailMap[(k.Vorname + ' ' + k.Name).trim()] = k.Email;
  emailMap[(k.Name + ' ' + k.Vorname).trim()] = k.Email;
}

// Fällige Stücke (nur mit Kamerad-Zuweisung)
const faellig = stuecke.filter(a => {
  if (!a.Naechste_Pruefung || !a.Kamerad) return false;
  const d = new Date(a.Naechste_Pruefung);
  return d <= horizon;
}).map(a => {
  const d = new Date(a.Naechste_Pruefung);
  const days = Math.round((d - today) / 86400000);
  return { ...a, _days: days };
});

// Gruppiere nach Kamerad
const grouped = {};
for (const a of faellig) {
  const name = a.Kamerad;
  if (!grouped[name]) grouped[name] = { name, email: emailMap[name] || null, items: [] };
  grouped[name].items.push(a);
}

// Nur Kameraden mit E-Mail-Adresse
const result = Object.values(grouped).filter(g => g.email);
if (!result.length) return [{ json: { anzahl: 0 } }];

return result.map(g => ({ json: g }));

const { name, email, items } = $json;
if (!items || !items.length) return [];

const rows = [...items].sort((a, b) => a._days - b._days).map(a => {
  const color = a._days < 0 ? '#ef4444' : a._days <= 7 ? '#f97316' : '#eab308';
  const dayLabel = a._days < 0
    ? (Math.abs(a._days) === 1 ? '1 Tag ueberfaellig' : Math.abs(a._days) + ' Tage ueberfaellig')
    : a._days === 0 ? 'Heute faellig' : 'in ' + a._days + (a._days === 1 ? ' Tag' : ' Tagen');
  const datum = new Date(a.Naechste_Pruefung).toLocaleDateString('de-DE');
  return '<tr>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb">' + (a.Ausruestungstyp || '-') + '</td>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb">' + (a.Seriennummer || '-') + '</td>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb">' + datum + '</td>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb;color:' + color + ';font-weight:600">' + dayLabel + '</td>'
    + '</tr>';
}).join('');

const subject = 'PSA-Pruefung: ' + items.length + ' Stueck zur Kontrolle';
const html = '<html><body style="font-family:sans-serif;max-width:600px;margin:0 auto;padding:20px;color:#111827">'
  + '<h2 style="margin-top:0;color:#1e3a5f">Hallo ' + name.split(' ')[0] + ',</h2>'
  + '<p>folgende deiner PSA-Ausruestungsstuecke haben in den naechsten 30 Tagen eine faellige oder ueberfaellige Pruefung:</p>'
  + '<table style="width:100%;border-collapse:collapse;font-size:14px">'
  + '<thead><tr style="background:#f3f4f6;text-align:left">'
  + '<th style="padding:8px">Typ</th><th style="padding:8px">Seriennummer</th>'
  + '<th style="padding:8px">Prueftermin</th><th style="padding:8px">Faelligkeit</th>'
  + '</tr></thead>'
  + '<tbody>' + rows + '</tbody>'
  + '</table>'
  + '<p style="margin-top:16px">Bitte melde dich beim Geraetwart, damit die Pruefung zeitnah durchgefuehrt werden kann.</p>'
  + '<p style="margin-top:24px;font-size:12px;color:#6b7280">Automatischer PSA-Pruefungs-Reminder – jeden Montag</p>'
  + '</body></html>';

return [{ json: { toEmail: email, subject, html } }];
